/* SQL ID : ExamQstnDAO.list 설 명 : 문제 리스트 조회 */ SELECT A.EXAM_ID AS examCd , A.EXAM_QSTN_NO AS examQstnSn , A.QSTN_SEQNO AS qstnNo , A.CNDDT_ID AS subNo , A.TTL AS TTL , A.QSTN_CTS AS qstnCts , A.EXMPL01 AS empl1 , A.EXMPL02 AS empl2 , A.EXMPL03 AS empl3 , A.EXMPL04 AS empl4 , A.EXMPL05 AS empl5 , A.EXMPL06 AS empl6 , A.EXMPL07 AS empl7 , A.EXMPL08 AS empl8 , A.EXMPL09 AS empl9 , A.EXMPL10 AS empl10 , A.MLT_CRANSYN AS multiRgtChoiceYn , A.MLT_CRANS_TYCD AS multiRgtChoiceTypeCd , A.MLT_CRANS AS multiRgtAnsr , A.RGT_ANSR1 AS rgtAnsr1 , A.RGT_ANSR2 AS rgtAnsr2 , A.RGT_ANSR3 AS rgtAnsr3 , A.CRANS4 AS rgtAnsr4 , A.CRANS5 AS rgtAnsr5 , A.QSTN_EXPLN AS qstnExpl , A.QSTN_TYCD AS qstnTypeCd , (SELECT MAX(CDNM) FROM TB_ORG_CODE WHERE CTGRCD = 'QSTN_TYCD' AND CD = A.QSTN_TYCD) AS qstnTypeNm , A.QSTN_SCR AS qstnScore , A.QSTN_DFCTLV AS qstnDiff , A.WHOL_CRANS_PROCYN AS errorAnsrYn , A.EDTRYN AS editorYn , A.DELYN AS delYn , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm ,(case when (NVL(length(trim(A.EXMPL01)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL02)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL03)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL04)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL05)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL06)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL07)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL08)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL09)),0) = 0) then 0 else 1 end + case when (NVL(length(trim(A.EXMPL10)),0) = 0) then 0 else 1 end ) AS emplCnt FROM TB_LMS_EXAM_QSTN A WHERE A.DELYN = 'N' AND A.EXAM_ID = #{examCd}
AND A.QSTN_SEQNO = #{qstnNo}
ORDER BY A.QSTN_SEQNO, A.CNDDT_ID

/* SQL ID : ExamQstnDAO.egovList 설 명 : 문제 전체 목록 조회 */ SELECT A.EXAM_ID AS examCd , A.EXAM_QSTN_NO AS examQstnSn , A.QSTN_SEQNO AS qstnNo , A.CNDDT_ID AS subNo , A.TTL AS TTL , A.QSTN_CTS AS qstnCts , A.EXMPL01 AS empl1 , A.EXMPL02 AS empl2 , A.EXMPL03 AS empl3 , A.EXMPL04 AS empl4 , A.EXMPL05 AS empl5 , A.EXMPL06 AS empl6 , A.EXMPL07 AS empl7 , A.EXMPL08 AS empl8 , A.EXMPL09 AS empl9 , A.EXMPL10 AS empl10 , A.MLT_CRANSYN AS multiRgtChoiceYn , A.MLT_CRANS_TYCD AS multiRgtChoiceTypeCd , A.MLT_CRANS AS multiRgtAnsr , A.RGT_ANSR1 AS rgtAnsr1 , A.RGT_ANSR2 AS rgtAnsr2 , A.RGT_ANSR3 AS rgtAnsr3 , A.CRANS4 AS rgtAnsr4 , A.CRANS5 AS rgtAnsr5 , A.QSTN_EXPLN AS qstnExpl , A.QSTN_TYCD AS qstnTypeCd , A.QSTN_SCR AS qstnScore , A.QSTN_DFCTLV AS qstnDiff , A.WHOL_CRANS_PROCYN AS errorAnsrYn , A.EDTRYN AS editorYn , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm FROM TB_LMS_EXAM_QSTN A WHERE 1=1 AND DELYN='N'
AND A.EXAM_ID = #{examCd}
AND A.EXAM_QSTN_NO = #{examQstnSn}
AND A.QSTN_SEQNO = #{qstnNo}
AND A.CNDDT_ID = #{subNo}
ORDER BY A.QSTN_SEQNO, A.CNDDT_ID

mapper.update:
		/*
		 	SQL ID : ExamQstnDAO.updateQstnNo
		 	설  명 : 문제 순서 변경
	 	*/
		UPDATE TB_LMS_EXAM_QSTN SET

    		QSTN_SEQNO = QSTN_SEQNO + 1


    		QSTN_SEQNO = QSTN_SEQNO - 1

    	 WHERE EXAM_ID = #{examCd}
    	   AND DELYN = 'N'

    	   AND QSTN_SEQNO BETWEEN #{newQstnNo} AND #{qstnNo}


    	   AND QSTN_SEQNO BETWEEN #{qstnNo} AND #{newQstnNo}


    	   AND EXAM_QSTN_NO != #{examQstnSn}

	/*
	 	SQL ID : ExamQstnDAO.updateQstnNoToNo
	 	설  명 : 문제 순서 특정 번호로 변경
 	*/
	UPDATE TB_LMS_EXAM_QSTN SET
		QSTN_SEQNO = #{newQstnNo}
	WHERE EXAM_ID = #{examCd}


			AND EXAM_QSTN_NO IN

	            #{item}

		/*
		 	SQL ID : ExamQstnDAO.updateSubNo
		 	설  명 : 문제 후보 순서 변경
	 	*/
		UPDATE TB_LMS_EXAM_QSTN SET

    		CNDDT_ID = CNDDT_ID + 1


    		CNDDT_ID = CNDDT_ID - 1

    	 WHERE EXAM_ID = #{examCd}
    	   AND DELYN = 'N'
    	   AND QSTN_SEQNO = #{qstnNo}

    	   AND CNDDT_ID BETWEEN #{newSubNo} AND #{subNo}


    	   AND CNDDT_ID BETWEEN #{subNo} AND #{newSubNo}


    	   AND EXAM_QSTN_NO != #{examQstnSn}

	/*
	 	SQL ID : ExamQstnDAO.updateSubNoToNo
	 	설  명 : 문제 후보 순서 특정 번호로 변경
 	*/
	UPDATE TB_LMS_EXAM_QSTN SET
		CNDDT_ID = #{newSubNo}
	WHERE EXAM_ID = #{examCd}
	  AND EXAM_QSTN_NO = #{examQstnSn}
	  AND QSTN_SEQNO = #{qstnNo}

