mapper.select:
	/*
	 	SQL ID : ExamQstnDAO.selectMaxSubNo
	 	설  명 : 문제 후보 번호 다음값 가져오기
 	*/
	SELECT
		IFNULL(MAX(CNDDT_ID), 0) + 1
	FROM TB_LMS_EXAM_QSTN
	WHERE EXAM_ID = #{examCd}
	  AND QSTN_SEQNO = #{qstnNo}
	  AND DELYN = 'N'

	/*
	 	SQL ID : ExamQstnDAO.selectOtherSubCount
	 	설  명 : 문제 후보 번호 다음 값 개수 카운트
 	*/
 	SELECT
 		COUNT(*)
 	  FROM TB_LMS_EXAM_QSTN
 	 WHERE EXAM_ID = #{examCd}
 	   AND DELYN = 'N'
 	   AND QSTN_SEQNO = #{qstnNo}
 	   AND CNDDT_ID != #{subNo}
